  // ── Public API ──────────────────────────────────────────────────────────────
  // v0.9.5: compile() uses multi-error parser — returns all parse errors at once
  function compile(source) {
    try {
      const tokens = new Lexer(source).tokenize()
      const { ast, errors: parseErrs } = new Parser(tokens).parse()
      const errors = parseErrs.map(e => ({
        message: e.message, line: e.line ?? 1, col: e.col ?? 1, kind: 'parse'
      }))
      if (errors.length > 0) return { js: null, errors, warnings: [] }
      const diags = new Checker().check(ast)
      const warnings = diags.map(d => ({
        severity: d.severity, message: d.message, line: d.line, col: d.col ?? 1,
      }))
      const js = new Codegen().generate(ast)
      return { js, errors: [], warnings }
    } catch (e) {
      return { js: null, errors: [{ message: String(e), line: 1, col: 1, kind: 'error' }], warnings: [] }
    }
  }

  function check(source) {
    try {
      const tokens = new Lexer(source).tokenize()
      const { ast, errors: parseErrs } = new Parser(tokens).parse()
      if (parseErrs.length > 0) {
        return { warnings: [], errors: parseErrs.map(e => ({ message: e.message, line: e.line, col: e.col })) }
      }
      const diags = new Checker().check(ast)
      return {
        warnings: diags.map(d => ({ severity: d.severity, message: d.message, line: d.line, col: d.col ?? 1 })),
        errors: []
      }
    } catch (e) {
      return { warnings: [], errors: [{ message: String(e), line: 1, col: 1 }] }
    }
  }

